sql:
SELECT cm.comment_text AS Comment, p.player_name AS Player
FROM comments cm
JOIN players p ON cm.user_id = p.team_id;

SELECT r.report_name, c.comment_text
FROM reports r
INNER JOIN comments c ON r.report_id = c.report_id;

SELECT player_name, position, date_of_birth, height, weight, college, draft_year, draft_round, draft_pick
FROM players
WHERE current_salary > (SELECT AVG(current_salary) FROM players);

SELECT g.date, g.opponent, g.location, g.attendance
FROM games g
ORDER BY g.attendance DESC;

external_knowledge:
- 'heavier-set players' implies players whose BMI is 25 or greater;
- The BMI is calculated using the weight (kg) divided by the square of the height (m);
- The age is determined by subtracting the date of birth from the current date.

sql:
SELECT report_name, data 
FROM reports 
WHERE created_by = (SELECT user_id FROM user_management WHERE username = 'analyst_mary');

SELECT DISTINCT u.username, u.email
FROM user_management AS u
JOIN reports AS r ON u.user_id = r.created_by;
